    const defaultVal = Array.isArray(val) ? [] : {}
    if (Array.isArray(obj[key]) !== Array.isArray(val)) {
      obj[key] = defaultVal
    } else {
      obj[key] ??= defaultVal
    }

    deepAssign(obj[key], val)
  } else {
    obj[key] = val
